class Matiere:
    def __init__(self, nom):
        self.nom = nom
        self.notes = []

    def ajouter_note(self, note):
        if 0 <= note <= 20:
            self.notes.append(note)
        else:
            print(f"Note invalide pour {self.nom}")

    def moyenne(self):
        return sum(self.notes) / len(self.notes) if self.notes else 0

class GestionNotes:
    def __init__(self):
        self.matieres = {}

    def ajouter_matiere(self, nom):
        self.matieres[nom] = Matiere(nom)

    def ajouter_note(self, matiere, note):
        if matiere in self.matieres:
            self.matieres[matiere].ajouter_note(note)
        else:
            print("Matière inconnue")

    def moyenne_matiere(self, matiere):
        return self.matieres[matiere].moyenne() if matiere in self.matieres else 0
```
Justification : plus de duplication, ajout facile de matières, respect DRY et KISS.

