class Commande:
    def __init__(self, plat, quantite, prix_unitaire):
        self.plat = plat
        self.quantite = quantite
        self.prix_unitaire = prix_unitaire

    def total_brut(self):
        return self.quantite * self.prix_unitaire

    def total_net(self):
        brut = self.total_brut()
        return CalculateurPrix.appliquer_reduction(brut)

def traiter_commande(commande):
    print(f"Traitement de {commande.quantite} x {commande.plat}")
    print(f"Montant brut: {commande.total_brut()} FCFA")
    print(f"À payer: {commande.total_net()} FCFA")
```
Justification : SRP respecté (Commande gère les données, CalculateurPrix gère les règles métier).

