from abc import ABC, abstractmethod

class StrategieReduction(ABC):
    @abstractmethod
    def appliquer(self, montant, commandes_precedentes=0):
        pass

class ReductionSeuil(StrategieReduction):
    def appliquer(self, montant, **kwargs):
        return montant * 0.9 if montant > 5000 else montant

class ReductionFidelite(StrategieReduction):
    def appliquer(self, montant, commandes_precedentes=0, **kwargs):
        if commandes_precedentes >= 3:
            return montant * 0.95
        return montant

class CalculateurPrix:
    def __init__(self, strategies):
        self.strategies = strategies

    def appliquer_toutes(self, montant, contexte):
        for strat in self.strategies:
            montant = strat.appliquer(montant, **contexte)
        return montant

# Utilisation
strat_list = [ReductionSeuil(), ReductionFidelite()]
calc = CalculateurPrix(strat_list)
montant_final = calc.appliquer_toutes(6000, {'commandes_precedentes': 3})
```
Ainsi on respecte OCP (ouvert/fermé).
